@namespace sv_fb6cae2ae9e84f4394eb61511569b0aa.Components.Application

<nav class="step-indicator mb-4" aria-label="Application progress">
    <ol class="d-flex list-unstyled justify-content-between position-relative px-0">
        @for (int i = 0; i < StepNames.Count; i++)
        {
            var step = i;
            var status = step < CurrentStep ? "completed"
                       : step == CurrentStep ? "active"
                       : "upcoming";
            var isClickable = step < CurrentStep;

            <li class="step-item text-center flex-fill @status" role="listitem">
                @if (isClickable)
                {
                    <button type="button" class="btn step-circle @status mx-auto d-flex align-items-center justify-content-center"
                            @onclick="() => OnStepClicked.InvokeAsync(step)"
                            aria-label="Go back to @StepNames[step]">
                        <span>✓</span>
                    </button>
                }
                else
                {
                    <div class="step-circle @status mx-auto d-flex align-items-center justify-content-center"
                         aria-current="@(status == "active" ? "step" : null)">
                        <span>@(step + 1)</span>
                    </div>
                }
                <div class="step-label mt-1 small @status">@StepNames[step]</div>
            </li>
        }
    </ol>
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public IReadOnlyList<string> StepNames { get; set; } = [];
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }
}

.step-indicator ol {
    counter-reset: step;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    border: 2px solid #dee2e6;
    background: #fff;
    font-weight: 600;
    font-size: 0.875rem;
    transition: all 0.2s;
}

.step-circle.completed {
    background: #198754;
    border-color: #198754;
    color: #fff;
    cursor: pointer;
    padding: 0;
}

.step-circle.completed:hover {
    background: #157347;
    border-color: #157347;
}

.step-circle.active {
    border-color: #0d6efd;
    background: #0d6efd;
    color: #fff;
}

.step-circle.upcoming {
    color: #adb5bd;
}

.step-label.completed {
    color: #198754;
    font-weight: 500;
}

.step-label.active {
    color: #0d6efd;
    font-weight: 600;
}

.step-label.upcoming {
    color: #adb5bd;
}

@namespace sv_fb6cae2ae9e84f4394eb61511569b0aa.Components.Application

<div class="work-entry card mb-3">
    <div class="card-body">
        @if (ShowRemove)
        {
            <button type="button" class="btn btn-sm btn-outline-danger float-end" @onclick="OnRemove">Remove</button>
        }

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Company Name <span class="text-danger">*</span></label>
                <input class="form-control" value="@Company" @onchange="e => Update(company: (string?)e.Value)" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                <input class="form-control" value="@Title" @onchange="e => Update(title: (string?)e.Value)" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Start Date <span class="text-danger">*</span></label>
                <input type="date" class="form-control" value="@FormatDate(StartDate)" @onchange="e => OnStartDateChange(e)" />
            </div>
            <div class="col-md-4">
                <label class="form-label">End Date</label>
                <input type="date" class="form-control" value="@FormatDate(EndDate)" disabled="@IsCurrent"
                       @onchange="e => OnEndDateChange(e)" />
            </div>
            <div class="col-md-4 d-flex align-items-end">
                <div class="form-check mb-2">
                    <input type="checkbox" class="form-check-input" checked="@IsCurrent"
                           @onchange="e => OnCurrentChanged((bool)(e.Value ?? false))" id="@_currentId" />
                    <label class="form-check-label" for="@_currentId">Currently working here</label>
                </div>
            </div>
            <div class="col-12">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="3" value="@Description"
                          @onchange="e => Update(description: (string?)e.Value)"></textarea>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter] public string Company { get; set; } = "";
    [Parameter] public string Title { get; set; } = "";
    [Parameter] public DateTime StartDate { get; set; }
    [Parameter] public DateTime? EndDate { get; set; }
    [Parameter] public string Description { get; set; } = "";
    [Parameter] public bool IsCurrent { get; set; }
    [Parameter] public bool ShowRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }
    [Parameter] public EventCallback<WorkEntryData> OnChanged { get; set; }

    private readonly string _currentId = $"current-{Guid.NewGuid():N}";

    public record WorkEntryData(string Company, string Title, DateTime StartDate, DateTime? EndDate, bool IsCurrent, string Description);

    private string FormatDate(DateTime? date) => date?.ToString("yyyy-MM-dd") ?? "";
    private string FormatDate(DateTime date) => date == default ? "" : date.ToString("yyyy-MM-dd");

    private void Update(string? company = null, string? title = null, DateTime? startDate = null,
                        DateTime? endDate = null, bool? isCurrent = null, string? description = null)
    {
        OnChanged.InvokeAsync(new WorkEntryData(
            company ?? Company,
            title ?? Title,
            startDate ?? StartDate,
            isCurrent ?? IsCurrent ? null : (endDate ?? EndDate),
            isCurrent ?? IsCurrent,
            description ?? Description
        ));
    }

    private void OnStartDateChange(ChangeEventArgs e)
    {
        if (DateTime.TryParse((string?)e.Value, out var d))
            Update(startDate: d);
    }

    private void OnEndDateChange(ChangeEventArgs e)
    {
        if (DateTime.TryParse((string?)e.Value, out var d))
            Update(endDate: d);
    }

    private void OnCurrentChanged(bool current)
    {
        Update(isCurrent: current);
    }
}

@namespace sv_fb6cae2ae9e84f4394eb61511569b0aa.Components.Application

<div class="reference-entry card mb-3">
    <div class="card-body">
        @if (ShowRemove)
        {
            <button type="button" class="btn btn-sm btn-outline-danger float-end" @onclick="OnRemove">Remove</button>
        }
        <h6 class="card-subtitle mb-3 text-body-secondary">Reference @(Index + 1)</h6>
        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Name <span class="text-danger">*</span></label>
                <input class="form-control" value="@Name" @onchange="e => Update(name: (string?)e.Value)" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Relationship <span class="text-danger">*</span></label>
                <input class="form-control" value="@Relationship" @onchange="e => Update(relationship: (string?)e.Value)" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Email <span class="text-danger">*</span></label>
                <input type="email" class="form-control" value="@Email" @onchange="e => Update(email: (string?)e.Value)" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Phone <span class="text-danger">*</span></label>
                <input type="tel" class="form-control" value="@Phone" @onchange="e => Update(phone: (string?)e.Value)" />
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter] public int Index { get; set; }
    [Parameter] public string Name { get; set; } = "";
    [Parameter] public string Relationship { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public bool ShowRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }
    [Parameter] public EventCallback<ReferenceData> OnChanged { get; set; }

    public record ReferenceData(string Name, string Relationship, string Email, string Phone);

    private void Update(string? name = null, string? relationship = null, string? email = null, string? phone = null)
    {
        OnChanged.InvokeAsync(new ReferenceData(
            name ?? Name,
            relationship ?? Relationship,
            email ?? Email,
            phone ?? Phone
        ));
    }
}

