@namespace sv_fb6cae2ae9e84f4394eb61511569b0aa.Components.Application

<h4 class="mb-3">Review & Submit</h4>

@if (_submitted)
{
    <div class="alert alert-success">
        <h5 class="alert-heading">Application Submitted!</h5>
        <p>Your application has been submitted successfully. Your application ID is <strong>@_applicationId</strong>.</p>
    </div>
}
else
{
    @if (!string.IsNullOrEmpty(_error))
    {
        <div class="alert alert-danger">@_error</div>
    }

    <!-- Personal Info -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button type="button" class="btn btn-sm btn-link" @onclick='() => OnEditSection.InvokeAsync(0)'>Edit</button>
        </div>
        <div class="card-body">
            <dl class="row mb-0">
                <dt class="col-sm-3">Full Name</dt>
                <dd class="col-sm-9">@FullName</dd>
                <dt class="col-sm-3">Email</dt>
                <dd class="col-sm-9">@Email</dd>
                <dt class="col-sm-3">Phone</dt>
                <dd class="col-sm-9">@Phone</dd>
                <dt class="col-sm-3">Address</dt>
                <dd class="col-sm-9">@Address</dd>
            </dl>
        </div>
    </div>

    <!-- Work History -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button type="button" class="btn btn-sm btn-link" @onclick='() => OnEditSection.InvokeAsync(1)'>Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-3 pb-3 border-bottom last-child-no-border">
                    <h6>@entry.Title at @entry.Company</h6>
                    <p class="text-body-secondary mb-1">
                        @entry.StartDate.ToString("MMM yyyy") –
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                    </p>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p class="mb-0">@entry.Description</p>
                    }
                </div>
            }
        </div>
    </div>

    <!-- References -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button type="button" class="btn btn-sm btn-link" @onclick='() => OnEditSection.InvokeAsync(2)'>Edit</button>
        </div>
        <div class="card-body">
            @foreach (var r in References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> — @r.Relationship<br />
                    <span class="text-body-secondary">@r.Email · @r.Phone</span>
                </div>
            }
        </div>
    </div>

    <!-- Cover Letter -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button type="button" class="btn btn-sm btn-link" @onclick='() => OnEditSection.InvokeAsync(3)'>Edit</button>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;">@CoverLetter</p>
        </div>
    </div>

    <div class="d-flex justify-content-between mt-4">
        <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@_submitting">
            @if (_submitting)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Submit Application
        </button>
    </div>
}

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public List<WorkHistoryStep.EntryModel> WorkEntries { get; set; } = [];
    [Parameter] public List<ReferencesStep.RefModel> References { get; set; } = [];
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<int> OnEditSection { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback<int> OnSubmitted { get; set; }
    [Parameter, EditorRequired] public Services.IApplicationService ApplicationService { get; set; } = default!;

    private bool _submitting;
    private bool _submitted;
    private int _applicationId;
    private string? _error;

    private async Task HandleSubmit()
    {
        _error = null;
        _submitting = true;
        try
        {
            var personal = new Models.PersonalInfo(FullName, Email, Phone, Address);
            var workHistory = new Models.WorkHistory(
                WorkEntries.Select(e => new Models.WorkEntry(
                    e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description
                )).ToList()
            );
            var refs = References.Select(r => new Models.Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();
            var application = new Models.JobApplication(personal, workHistory, refs, CoverLetter);

            _applicationId = await ApplicationService.SubmitApplicationAsync(application);
            _submitted = true;
            await OnSubmitted.InvokeAsync(_applicationId);
        }
        catch (Exception ex)
        {
            _error = $"Submission failed: {ex.Message}. Please try again.";
        }
        finally
        {
            _submitting = false;
        }
    }
}

