@namespace sv_fb6cae2ae9e84f4394eb61511569b0aa.Components.Application

<h4 class="mb-3">Work History</h4>

@if (!string.IsNullOrEmpty(_error))
{
    <div class="alert alert-danger">@_error</div>
}

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    var entry = Entries[index];
    <WorkEntryEditor Company="@entry.Company"
                     Title="@entry.Title"
                     StartDate="@entry.StartDate"
                     EndDate="@entry.EndDate"
                     IsCurrent="@entry.IsCurrent"
                     Description="@entry.Description"
                     ShowRemove="@(Entries.Count > 1)"
                     OnRemove="() => RemoveEntry(index)"
                     OnChanged="data => UpdateEntry(index, data)" />
}

<button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

<div class="d-flex justify-content-between mt-4">
    <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter] public List<EntryModel> Entries { get; set; } = [];
    [Parameter] public EventCallback<List<EntryModel>> EntriesChanged { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }

    private string? _error;

    public class EntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = "";
    }

    private void UpdateEntry(int index, WorkEntryEditor.WorkEntryData data)
    {
        var entry = Entries[index];
        entry.Company = data.Company;
        entry.Title = data.Title;
        entry.StartDate = data.StartDate;
        entry.EndDate = data.EndDate;
        entry.IsCurrent = data.IsCurrent;
        entry.Description = data.Description;
        EntriesChanged.InvokeAsync(Entries);
    }

    private void AddEntry()
    {
        Entries.Add(new EntryModel());
        EntriesChanged.InvokeAsync(Entries);
    }

    private void RemoveEntry(int index)
    {
        Entries.RemoveAt(index);
        EntriesChanged.InvokeAsync(Entries);
    }

    private async Task HandleNext()
    {
        _error = null;
        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title) ||
                entry.StartDate == default)
            {
                _error = "Each work entry must have a company name, job title, and start date.";
                return;
            }
        }
        await OnNext.InvokeAsync();
    }
}

