@namespace sv_fb6cae2ae9e84f4394eb61511569b0aa.Components.Application

<h4 class="mb-3">Personal Information</h4>

@if (!string.IsNullOrEmpty(_error))
{
    <div class="alert alert-danger">@_error</div>
}

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input class="form-control" value="@FullName" @onchange="e => FullNameChanged.InvokeAsync((string?)e.Value ?? "")" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control" value="@Email" @onchange="e => EmailChanged.InvokeAsync((string?)e.Value ?? "")" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control" value="@Phone" @onchange="e => PhoneChanged.InvokeAsync((string?)e.Value ?? "")" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input class="form-control" value="@Address" @onchange="e => AddressChanged.InvokeAsync((string?)e.Value ?? "")" />
    </div>
</div>

<div class="d-flex justify-content-end mt-4">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@_validating">
        @if (_validating)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
        }
        Next
    </button>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public EventCallback<string> FullNameChanged { get; set; }
    [Parameter] public EventCallback<string> EmailChanged { get; set; }
    [Parameter] public EventCallback<string> PhoneChanged { get; set; }
    [Parameter] public EventCallback<string> AddressChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public Services.IApplicationService ApplicationService { get; set; } = default!;

    private string? _error;
    private bool _validating;

    private async Task HandleNext()
    {
        _error = null;

        if (string.IsNullOrWhiteSpace(FullName) || string.IsNullOrWhiteSpace(Email) ||
            string.IsNullOrWhiteSpace(Phone) || string.IsNullOrWhiteSpace(Address))
        {
            _error = "All fields are required.";
            return;
        }

        _validating = true;
        try
        {
            var isValid = await ApplicationService.ValidateEmailAsync(Email);
            if (!isValid)
            {
                _error = "The email address is not valid. Please enter a valid email.";
                return;
            }
            await OnNext.InvokeAsync();
        }
        finally
        {
            _validating = false;
        }
    }
}

