@namespace sv_fb6cae2ae9e84f4394eb61511569b0aa.Components.Application

<h4 class="mb-3">References</h4>

@if (!string.IsNullOrEmpty(_error))
{
    <div class="alert alert-danger">@_error</div>
}

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    var r = References[index];
    <ReferenceEditor Index="index"
                     Name="@r.Name"
                     Relationship="@r.Relationship"
                     Email="@r.Email"
                     Phone="@r.Phone"
                     ShowRemove="@(References.Count > 2)"
                     OnRemove="() => RemoveReference(index)"
                     OnChanged="data => UpdateReference(index, data)" />
}

@if (References.Count < 3)
{
    <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddReference">
        + Add Reference
    </button>
}

<div class="d-flex justify-content-between mt-4">
    <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter] public List<RefModel> References { get; set; } = [];
    [Parameter] public EventCallback<List<RefModel>> ReferencesChanged { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }

    private string? _error;

    public class RefModel
    {
        public string Name { get; set; } = "";
        public string Relationship { get; set; } = "";
        public string Email { get; set; } = "";
        public string Phone { get; set; } = "";
    }

    private void UpdateReference(int index, ReferenceEditor.ReferenceData data)
    {
        var r = References[index];
        r.Name = data.Name;
        r.Relationship = data.Relationship;
        r.Email = data.Email;
        r.Phone = data.Phone;
        ReferencesChanged.InvokeAsync(References);
    }

    private void AddReference()
    {
        if (References.Count < 3)
        {
            References.Add(new RefModel());
            ReferencesChanged.InvokeAsync(References);
        }
    }

    private void RemoveReference(int index)
    {
        References.RemoveAt(index);
        ReferencesChanged.InvokeAsync(References);
    }

