@page "/apply"
@rendermode InteractiveServer
@using sv_fb6cae2ae9e84f4394eb61511569b0aa.Components.Application
@using sv_fb6cae2ae9e84f4394eb61511569b0aa.Services
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="_currentStep" StepNames="_stepNames" OnStepClicked="GoToStep" />

    @switch (_currentStep)
    {
        case 0:
            <PersonalInfoStep FullName="@_fullName" Email="@_email" Phone="@_phone" Address="@_address"
                              FullNameChanged="v => _fullName = v" EmailChanged="v => _email = v"
                              PhoneChanged="v => _phone = v" AddressChanged="v => _address = v"
                              OnNext="NextStep" ApplicationService="ApplicationService" />
            break;

        case 1:
            <WorkHistoryStep Entries="_workEntries" EntriesChanged="v => _workEntries = v"
                             OnBack="PrevStep" OnNext="NextStep" />
            break;

        case 2:
            <ReferencesStep References="_references" ReferencesChanged="v => _references = v"
                            OnBack="PrevStep" OnNext="NextStep" />
            break;

        case 3:
            <CoverLetterStep CoverLetter="@_coverLetter" CoverLetterChanged="v => _coverLetter = v"
                             OnBack="PrevStep" OnNext="NextStep" />
            break;

        case 4:
            <ReviewStep FullName="@_fullName" Email="@_email" Phone="@_phone" Address="@_address"
                        WorkEntries="_workEntries" References="_references" CoverLetter="@_coverLetter"
                        OnEditSection="GoToStep" OnBack="PrevStep" OnSubmitted="id => _applicationId = id"
                        ApplicationService="ApplicationService" />
            break;
    }
</div>

@code {
    private static readonly IReadOnlyList<string> _stepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    private int _currentStep;
    private int? _applicationId;

    // Step 1 — Personal Info
    private string _fullName = "";
    private string _email = "";
    private string _phone = "";
    private string _address = "";

    // Step 2 — Work History
    private List<WorkHistoryStep.EntryModel> _workEntries = [new()];

    // Step 3 — References
    private List<ReferencesStep.RefModel> _references = [new(), new()];

    // Step 4 — Cover Letter
    private string _coverLetter = "";

    private void NextStep() => _currentStep = Math.Min(_currentStep + 1, _stepNames.Count - 1);
    private void PrevStep() => _currentStep = Math.Max(_currentStep - 1, 0);
    private void GoToStep(int step)
    {
        if (step < _currentStep)
            _currentStep = step;
    }
}

